'use client';

import { useRef, useState } from 'react';
import { motion, useScroll, useTransform, useReducedMotion } from 'framer-motion';
import { Code, Brain, BookOpen, Award, Zap, Target, Users, Rocket } from 'lucide-react';
import { aboutRoles, expertiseByCategory, operatingPrinciples } from '@/lib/site-content';

const roles = [
  { icon: Code, ...aboutRoles[0] },
  { icon: Brain, ...aboutRoles[1] },
  { icon: BookOpen, ...aboutRoles[2] },
  { icon: Award, ...aboutRoles[3] },
];

const values = [
  { icon: Target, label: 'Precision' },
  { icon: Zap, label: 'Efficiency' },
  { icon: Users, label: 'Human-Centric' },
  { icon: Rocket, label: 'Innovation' },
];

export function EnhancedAboutSection() {
  const containerRef = useRef<HTMLDivElement>(null);
  const [activeSkill, setActiveSkill] = useState<string | null>(null);
  const prefersReducedMotion = useReducedMotion();

  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ['start end', 'end start'],
  });

  const y = useTransform(scrollYProgress, [0, 1], [50, -50]);
  const opacity = useTransform(scrollYProgress, [0, 0.2, 0.8, 1], [0.5, 1, 1, 0.5]);

  return (
    <section id="about" className="section-spacing bg-muted/30 relative overflow-hidden" ref={containerRef}>
      {/* Animated Background */}
      <motion.div 
        style={{ y: prefersReducedMotion ? 0 : y, opacity }}
        className="absolute inset-0 pointer-events-none"
      >
        <div className="absolute top-20 right-20 w-64 h-64 bg-primary/5 rounded-full blur-3xl" />
        <div className="absolute bottom-20 left-20 w-96 h-96 bg-primary/3 rounded-full blur-3xl" />
      </motion.div>

      <div className="editorial-container relative z-10">
        {/* Section Header */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.5 }}
          className="mb-16"
        >
          <div className="flex items-center gap-3 mb-4">
            <span className="font-mono text-xs text-muted-foreground">{'// 01'}</span>
            <div className="h-px flex-1 bg-gradient-to-r from-border to-transparent" />
          </div>

          {/* ASCII Art Header */}
          <div className="mb-8 hidden md:block">
            <pre className="font-mono text-[10px] text-muted-foreground/40">
{`╭────────────────────────────────────────────────────────────────────────────╮
│                                                                            │
│    "Technology is best when it brings people together." — Matt Mullenweg   │
│                                                                            │
╰────────────────────────────────────────────────────────────────────────────╯`}
            </pre>
          </div>

          <h2 className="editorial-title mb-4">
            Philosophy & Approach
          </h2>
          <p className="editorial-subtitle max-w-2xl">
            I believe in the power of technology to amplify human potential. 
              Whether architecting complex systems, integrating AI capabilities,
              or writing about personal development, my work centers on creating meaningful impact.
          </p>
        </motion.div>

        {/* Video Frame - 9:12 vertical video */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          className="mb-16 flex justify-center"
        >
          <div className="relative w-full max-w-lg aspect-[3/4] h-[70vh] max-h-[800px] rounded-xl overflow-hidden border-2 border-border bg-black">
            <video
              autoPlay
              loop
              muted
              playsInline
              poster="/media/dougie-frame-poster.webp"
              className="w-full h-full object-cover"
            >
              <source src="/media/dougie-frame-loop.mp4" type="video/mp4" />
            </video>
          </div>
        </motion.div>

        {/* Values Strip */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          className="flex justify-center gap-8 mb-16"
        >
          {values.map((value, index) => (
            <motion.div
              key={value.label}
              initial={{ opacity: 0, scale: 0.9 }}
              whileInView={{ opacity: 1, scale: 1 }}
              viewport={{ once: true }}
              transition={{ delay: index * 0.1 }}
              whileHover={{ scale: 1.1 }}
              className="flex flex-col items-center gap-2 group cursor-default"
            >
              <div className="w-12 h-12 rounded-full bg-background border border-border flex items-center justify-center group-hover:border-primary/50 group-hover:bg-primary/5 transition-all">
                <value.icon className="h-5 w-5 text-muted-foreground group-hover:text-primary transition-colors" />
              </div>
              <span className="font-mono text-xs text-muted-foreground">{value.label}</span>
            </motion.div>
          ))}
        </motion.div>

        {/* Roles Grid */}
        <motion.div
          initial={{ opacity: 0 }}
          whileInView={{ opacity: 1 }}
          viewport={{ once: true }}
          className="grid md:grid-cols-2 lg:grid-cols-4 gap-4 mb-16"
        >
          {roles.map((role, index) => (
            <motion.div
              key={role.title}
              initial={{ opacity: 0, y: 30 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 0.5, delay: index * 0.1 }}
              whileHover={{ y: -5 }}
              className="group relative proof-card bg-background"
            >
              {/* Corner Decoration */}
              <div className="absolute top-2 right-2 font-mono text-xs text-muted-foreground/30 group-hover:text-primary/50 transition-colors">
                [{String(index + 1).padStart(2, '0')}]
              </div>

              <div className="w-12 h-12 rounded-xl bg-primary/10 flex items-center justify-center mb-4 group-hover:scale-110 group-hover:bg-primary/20 transition-all">
                <role.icon className="h-6 w-6 text-primary" />
              </div>

              <h3 className="font-semibold mb-2">{role.title}</h3>

              <p className="text-sm text-muted-foreground leading-relaxed mb-4">
                {role.description}
              </p>

              <div className="font-mono text-xs text-primary/70 border-t border-border pt-3">
                {role.stats}
              </div>
            </motion.div>
          ))}
        </motion.div>

        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.5, delay: 0.15 }}
          className="mb-16 grid gap-4 lg:grid-cols-3"
        >
          {operatingPrinciples.map((principle, index) => (
            <motion.div
              key={principle.title}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: 0.1 * index }}
              className="rounded-2xl border border-border bg-background p-5"
            >
              <div className="font-mono text-xs uppercase tracking-[0.2em] text-primary">
                {principle.title}
              </div>
              <p className="mt-3 text-sm leading-relaxed text-muted-foreground">
                {principle.description}
              </p>
            </motion.div>
          ))}
        </motion.div>

        {/* Technical Expertise */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.5, delay: 0.2 }}
          className="border border-border rounded-xl overflow-hidden bg-background"
        >
          {/* Terminal Header */}
          <div className="flex items-center gap-2 px-4 py-3 border-b border-border bg-muted/30">
            <div className="flex gap-1.5">
              <div className="w-2.5 h-2.5 rounded-full bg-red-500/60" />
              <div className="w-2.5 h-2.5 rounded-full bg-yellow-500/60" />
              <div className="w-2.5 h-2.5 rounded-full bg-green-500/60" />
            </div>
            <span className="font-mono text-xs text-muted-foreground ml-2">
              technical_expertise.json
            </span>
          </div>

          {/* Skills Grid */}
          <div className="p-6 md:p-8">
            <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-8">
              {Object.entries(expertiseByCategory).map(([category, items], catIndex) => (
                <motion.div
                  key={category}
                  initial={{ opacity: 0, x: -10 }}
                  whileInView={{ opacity: 1, x: 0 }}
                  viewport={{ once: true }}
                  transition={{ delay: catIndex * 0.1 }}
                >
                  <div className="font-mono text-xs text-muted-foreground mb-3 flex items-center gap-2">
                    <span className="text-primary">{`"${category}"`}</span>
                    <span>:</span>
                  </div>
                  <div className="flex flex-wrap gap-1.5">
                    {items.map((skill, skillIndex) => (
                      <motion.span
                        key={skill}
                        initial={{ opacity: 0, scale: 0.8 }}
                        whileInView={{ opacity: 1, scale: 1 }}
                        viewport={{ once: true }}
                        transition={{ delay: catIndex * 0.1 + skillIndex * 0.05 }}
                        onHoverStart={() => setActiveSkill(skill)}
                        onHoverEnd={() => setActiveSkill(null)}
                        className={`px-3 py-1.5 text-xs font-mono rounded-lg cursor-default transition-all ${
                          activeSkill === skill 
                            ? 'bg-primary text-primary-foreground scale-105' 
                            : 'bg-muted hover:bg-muted/80'
                        }`}
                      >
                        {skill}
                      </motion.span>
                    ))}
                  </div>
                </motion.div>
              ))}
            </div>
          </div>
        </motion.div>

        {/* ASCII Footer */}
        <motion.div
          initial={{ opacity: 0 }}
          whileInView={{ opacity: 1 }}
          viewport={{ once: true }}
          className="mt-12 text-center"
        >
          <pre className="font-mono text-[10px] text-muted-foreground/30 inline-block">
{`┌─────────────────────────────────────────┐
│  Continuous learning in emerging tech   │
│         ~ Always exploring ~            │
└─────────────────────────────────────────┘`}
          </pre>
        </motion.div>
      </div>
    </section>
  );
}

src/components/effects/splash-overlay.tsx:
'use client';

import { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence, useReducedMotion } from 'framer-motion';

const KATAKANA = 'アイウエオカキクケコサシスセソタチツテトナニヌネノハヒフヘホマミムメモヤユヨラリルレロワヲン';

// Large ASCII art for name
const ASCII_NAME = `
██████╗  ██████╗ ██╗   ██╗ ██████╗ ██╗      █████╗ ███████╗
██╔══██╗██╔═══██╗██║   ██║██╔═══██╗██║     ██╔══██╗██╔════╝
██║  ██║██║   ██║██║   ██║██║   ██║██║     ███████║███████╗
██║  ██║██║   ██║██║   ██║██║   ██║██║     ██╔══██║╚════██║
██████╔╝╚██████╔╝╚██████╔╝╚██████╔╝███████╗██║  ██║███████║
╚═════╝  ╚═════╝  ╚═════╝  ╚═════╝ ╚══════╝╚═╝  ╚═╝╚══════╝

███╗   ███╗██╗████████╗ ██████╗██╗  ██╗███████╗██╗     ██╗         
████╗ ████║██║╚══██╔══╝██╔════╝██║  ██║██╔════╝██║     ██║         
██╔████╔██║██║   ██║   ██║     ███████║█████╗  ██║     ██║         
██║╚██╔╝██║██║   ██║   ██║     ██╔══██║██╔══╝  ██║     ██║         
██║ ╚═╝ ██║██║   ██║   ╚██████╗██║  ██║███████╗███████╗███████╗    
╚═╝     ╚═╝╚═╝   ╚═╝    ╚═════╝╚═╝  ╚═╝╚══════╝╚══════╝╚══════╝`;

const SUBTITLE = 'THE ARCHITECT';
const ROLES = [
  'Operations Analyst',
  'AI Practitioner',
  'Systems Architect',
  'Author',
  'Google AI Certified',
  'Anthropic Certified',
];

interface SplashOverlayProps {
  onComplete?: () => void;
  minDisplayTime?: number;
}

function createMatrixCharacters(length: number) {
  return Array.from({ length }, () => KATAKANA[Math.floor(Math.random() * KATAKANA.length)]);
}

export function SplashOverlay({ onComplete, minDisplayTime = 4000 }: SplashOverlayProps) {
  const [isVisible, setIsVisible] = useState(() => {
    if (typeof window === 'undefined') return true;
    return !sessionStorage.getItem('splash-seen');
  });
  const [phase, setPhase] = useState<'video' | 'matrix' | 'build' | 'reveal' | 'fade'>('video');
  const [matrixChars, setMatrixChars] = useState<string[]>(() => createMatrixCharacters(150));
  const [typedLines, setTypedLines] = useState<string[]>([]);
  const [currentLine, setCurrentLine] = useState(0);
  const [progress, setProgress] = useState(0);
  const [currentRole, setCurrentRole] = useState(0);
  const prefersReducedMotion = useReducedMotion();

  useEffect(() => {
    if (!isVisible) {
      onComplete?.();
    }
  }, [isVisible, onComplete]);

  // Video intro phase
  useEffect(() => {
    if (!isVisible || prefersReducedMotion || phase !== 'video') return;

    const timer = setTimeout(() => {
      setPhase('matrix');
    }, 2000);

    return () => clearTimeout(timer);
  }, [isVisible, prefersReducedMotion, phase]);

  // Matrix rain effect
  useEffect(() => {
    if (!isVisible || prefersReducedMotion) return;

    const interval = setInterval(() => {
      setMatrixChars(prev => prev.map(() => 
        Math.random() > 0.7 
          ? KATAKANA[Math.floor(Math.random() * KATAKANA.length)]
          : prev[Math.floor(Math.random() * prev.length)]
      ));
    }, 100);

    // Transition to build phase
    const timeout = setTimeout(() => {
      setPhase('build');
      clearInterval(interval);
    }, 1000);

    return () => {
      clearInterval(interval);
      clearTimeout(timeout);
    };
  }, [isVisible, prefersReducedMotion]);

  // Build phase - type out ASCII art
  useEffect(() => {
    if (phase !== 'build' || prefersReducedMotion) return;

    const lines = ASCII_NAME.split('\n').filter(line => line.trim());

    const typeInterval = setInterval(() => {
      setTypedLines(prev => {
        if (currentLine >= lines.length) {
          clearInterval(typeInterval);
          setTimeout(() => setPhase('reveal'), 500);
          return prev;
        }

        const line = lines[currentLine];
        const currentTyped = prev[currentLine] || '';

        if (currentTyped.length < line.length) {
          const next = [...prev];
          next[currentLine] = line.slice(0, currentTyped.length + 3);
          return next;
        } else {
          setCurrentLine(currentLine + 1);
          return [...prev, line];
        }
      });
    }, 30);

    return () => clearInterval(typeInterval);
  }, [phase, currentLine, prefersReducedMotion]);

  // Progress bar animation
  useEffect(() => {
    if (phase !== 'reveal') return;

    const interval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 100) {
          clearInterval(interval);
          setTimeout(() => setPhase('fade'), 500);
          return 100;
        }
        return prev + 2;
      });
    }, 50);

    return () => clearInterval(interval);
  }, [phase]);

  // Role rotation
  useEffect(() => {
    if (phase !== 'reveal') return;

    const interval = setInterval(() => {
      setCurrentRole(prev => (prev + 1) % ROLES.length);
    }, 800);

    return () => clearInterval(interval);
  }, [phase]);

  // Complete splash
  useEffect(() => {
    if (phase !== 'fade') return;

    const timeout = setTimeout(() => {
      sessionStorage.setItem('splash-seen', 'true');
      setIsVisible(false);
    }, Math.max(500, Math.round(minDisplayTime / 8)));

    return () => clearTimeout(timeout);
  }, [minDisplayTime, phase]);

  const handleSkip = useCallback(() => {
    sessionStorage.setItem('splash-seen', 'true');
    setIsVisible(false);
  }, []);

  // Skip on escape key
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') handleSkip();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleSkip]);

  if (!isVisible) return null;

  // Reduced motion version - simple fade
  if (prefersReducedMotion) {
    return (
      <motion.div
        initial={{ opacity: 1 }}
        animate={{ opacity: 0 }}
        transition={{ duration: 0.5, delay: 0.5 }}
        className="fixed inset-0 z-[9999] bg-background flex items-center justify-center"
        onClick={handleSkip}
      >
        <div className="text-center">
          <p className="font-mono text-sm text-muted-foreground">Loading...</p>
        </div>
      </motion.div>
    );
  }

  return (
    <AnimatePresence>
      {isVisible && (
        <motion.div
          initial={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          transition={{ duration: 0.5 }}
          className="fixed inset-0 z-[9999] bg-black flex flex-col items-center justify-center overflow-hidden cursor-pointer"
          onClick={handleSkip}
        >
          {/* Video Intro Phase */}
          {phase === 'video' && (
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="absolute inset-0 flex items-center justify-center"
            >
              <video
                autoPlay
                muted
                playsInline
                poster="/media/breathing-dm-poster.webp"
                className="w-full h-full object-contain max-w-2xl"
              >
                <source src="/media/breathing-dm-loop.mp4" type="video/mp4" />
              </video>
            </motion.div>
          )}

          {/* Matrix Rain Background */}
          {phase === 'matrix' && (
            <motion.div
              initial={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="absolute inset-0 grid grid-cols-[repeat(15,1fr)] gap-1 p-8 pointer-events-none"
            >
              {matrixChars.map((char, i) => (
                <motion.span
                  key={i}
                  initial={{ opacity: 0, y: -20 }}
                  animate={{ opacity: [0, 1, 0.3], y: 0 }}
                  transition={{ duration: 0.5, delay: i * 0.01 }}
                  className="font-mono text-green-500/40 text-lg"
                  style={{
                    textShadow: '0 0 10px rgba(34, 197, 94, 0.5)',
                  }}
                >
                  {char}
                </motion.span>
              ))}
            </motion.div>
          )}

          {/* Main Content */}
          <div className="relative z-10 text-center px-4">
            {/* Terminal Header */}
            <motion.div
              initial={{ opacity: 0, y: -20 }}
              animate={{ opacity: 1, y: 0 }}
              className="mb-8"
            >
              <div className="inline-flex items-center gap-2 px-4 py-2 border border-green-500/30 rounded-lg bg-green-500/5">
                <div className="flex gap-1.5">
                  <div className="w-2.5 h-2.5 rounded-full bg-red-500/60" />
                  <div className="w-2.5 h-2.5 rounded-full bg-yellow-500/60" />
                  <div className="w-2.5 h-2.5 rounded-full bg-green-500/60" />
                </div>
                <span className="font-mono text-xs text-green-500/70">
                  douglas-mitchell-system-v4.2.0
                </span>
              </div>
            </motion.div>

            {/* ASCII Art */}
            {(phase === 'build' || phase === 'reveal' || phase === 'fade') && (
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="mb-6"
              >
                <pre className="font-mono text-[6px] sm:text-[8px] md:text-[10px] lg:text-xs text-green-500 leading-none tracking-tighter whitespace-pre overflow-hidden">
                  {typedLines.map((line, i) => (
                    <motion.div
                      key={i}
                      initial={{ opacity: 0, x: -20 }}
                      animate={{ opacity: 1, x: 0 }}
                      transition={{ delay: i * 0.05 }}
                    >
                      {line}
                    </motion.div>
                  ))}
                </pre>
              </motion.div>
            )}

            {/* Subtitle */}
            {phase === 'reveal' && (
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="mb-8"
              >
                <div className="flex items-center justify-center gap-4">
                  <span className="font-mono text-green-500/30">{'◄'}</span>
                  <span className="font-mono text-lg text-green-400 tracking-widest">
                    {SUBTITLE}
                  </span>
                  <span className="font-mono text-green-500/30">{'►'}</span>
                </div>
              </motion.div>
            )}

            {/* Rotating Role */}
            {phase === 'reveal' && (
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="mb-8 h-8"
              >
                <div className="flex items-center justify-center gap-3">
                  <span className="font-mono text-xs text-green-500/50">$</span>
                  <motion.span
                    key={currentRole}
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, y: -10 }}
                    className="font-mono text-sm text-green-400"
                  >
                    {ROLES[currentRole]}
                  </motion.span>
                  <motion.span
                    animate={{ opacity: [1, 0] }}
                    transition={{ duration: 0.5, repeat: Infinity }}
                    className="font-mono text-green-500"
                  >
                    ▊
                  </motion.span>
                </div>
              </motion.div>
            )}

            {/* Progress Bar */}
            {phase === 'reveal' && (
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="w-64 sm:w-80 mx-auto"
              >
                <div className="flex items-center gap-2 mb-2">
                  <span className="font-mono text-xs text-green-500/50">loading...</span>
                  <span className="font-mono text-xs text-green-400">{progress}%</span>
                </div>
                <div className="h-1 bg-green-500/20 rounded-full overflow-hidden">
                  <motion.div
                    className="h-full bg-green-500"
                    initial={{ width: 0 }}
                    animate={{ width: `${progress}%` }}
                    transition={{ duration: 0.1 }}
                  />
                </div>
                <div className="mt-2 font-mono text-[10px] text-green-500/30">
                  {'['}{'█'.repeat(Math.floor(progress / 5))}{'░'.repeat(20 - Math.floor(progress / 5))}{']'}
                </div>
              </motion.div>
            )}

            {/* Footer */}
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 1 }}
              className="absolute bottom-8 left-0 right-0 text-center"
            >
              <p className="font-mono text-xs text-green-500/40">
                Press <kbd className="px-1.5 py-0.5 bg-green-500/10 rounded text-green-500/60">ESC</kbd> or click to skip
              </p>
            </motion.div>

            {/* Corner Decorations */}
            <div className="absolute top-8 left-8 font-mono text-xs text-green-500/30">
              ╭──────────────────╮
            </div>
            <div className="absolute top-8 right-8 font-mono text-xs text-green-500/30">
              ╭──────────────────╮
            </div>
            <div className="absolute bottom-8 left-8 font-mono text-xs text-green-500/30">
              ╰──────────────────╯
            </div>
            <div className="absolute bottom-8 right-8 font-mono text-xs text-green-500/30">
              ╰──────────────────╯
            </div>
          </div>

          {/* Scanline Effect */}
          <div 
            className="absolute inset-0 pointer-events-none opacity-10"
            style={{
              background: 'repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(0,255,0,0.03) 2px, rgba(0,255,0,0.03) 4px)',
            }}
          />
        </motion.div>
      )}
    </AnimatePresence>
  );
}


