    │                                    │
    │    • Operations Analysis          │
    │    • AI & Automation              │
    │    • Systems Design               │
    │    • Human Potential              │
    │                                    │
    ╰────────────────────────────────────╯`;

export function EnhancedHeroSection() {
  const [displayedRole, setDisplayedRole] = useState(0);
  const [typedText, setTypedText] = useState('');
  const [showAscii, setShowAscii] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const prefersReducedMotion = useReducedMotion();

  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ['start start', 'end start'],
  });

  const y = useTransform(scrollYProgress, [0, 1], ['0%', '50%']);
  const opacity = useTransform(scrollYProgress, [0, 0.5], [1, 0]);
  const scale = useTransform(scrollYProgress, [0, 0.5], [1, 0.9]);

  // Role rotation
  useEffect(() => {
    if (prefersReducedMotion) return;
    const interval = setInterval(() => {
      setDisplayedRole(prev => (prev + 1) % roles.length);
    }, 3000);
    return () => clearInterval(interval);
  }, [prefersReducedMotion]);

  // Typewriter effect for ASCII
  useEffect(() => {
    if (prefersReducedMotion) {
      setTypedText(asciiArt);
      setShowAscii(true);
      return;
    }

    const timeout = setTimeout(() => setShowAscii(true), 500);
    let charIndex = 0;

    const typeInterval = setInterval(() => {
      if (charIndex < asciiArt.length) {
        setTypedText(asciiArt.slice(0, charIndex + 1));
        charIndex++;
      } else {
        clearInterval(typeInterval);
      }
    }, 5);

    return () => {
      clearTimeout(timeout);
      clearInterval(typeInterval);
    };
  }, [prefersReducedMotion]);

  return (
    <section 
      ref={containerRef}
      className="relative min-h-screen flex items-center justify-center overflow-hidden"
    >
      {/* ASCII Grid Background */}
      <div 
        className="absolute inset-0 opacity-[0.02] dark:opacity-[0.05] z-[1]"
        aria-hidden="true"
      >
        <svg width="100%" height="100%" xmlns="http://www.w3.org/2000/svg">
          <defs>
